178: function formatMarkdown(text: string) {
179:   let html = text
180:     .replace(/^### (.*$)/gim, '<h3 class="text-xl font-semibold mt-6 mb-3 text-white">$1</h3>')
181:     .replace(/^## (.*$)/gim, '<h2 class="text-2xl font-bold mt-8 mb-4 border-b border-slate-800 pb-2 text-white">$1</h2>')
182:     .replace(/^# (.*$)/gim, '<h1 class="text-3xl font-bold mt-10 mb-6 text-white">$1</h1>')
183:     .replace(/\*\*(.*)\*\*/gim, '<strong class="text-white">$1</strong>')
184:     .replace(/\*(.*)\*/gim, '<em>$1</em>')
185:     .replace(/\n\n/g, '</p><p class="mb-4">')
186:     .replace(/\n/g, '<br />');
187:     
188:   html = html.replace(/- (.*$)/gim, '<li class="ml-4 list-disc mb-1">$1</li>');
189:   
190:   return `<p class="mb-4">${html}</p>`;
191: }
