"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Search, Loader2, ArrowLeft, Download, Share2, Activity, PieChart, AlertTriangle } from "lucide-react";
import Link from "next/link";
import { Navbar } from "@/components/layout/Navbar";

export default function ResearchPage() {
  const [companyName, setCompanyName] = useState("");
  const [loading, setLoading] = useState(false);
  const [logs, setLogs] = useState<{ node: string; message: string }[]>([]);
  const [result, setResult] = useState<{ verdict: string; report: string } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const logsEndRef = useRef<HTMLDivElement>(null);

  const startResearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!companyName) return;

    setLoading(true);
    setLogs([]);
    setResult(null);
    setError(null);

    try {
      const res = await fetch("/api/research", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ companyName }),
      });

      if (!res.ok) {
        throw new Error("Failed to start research");
      }

      const reader = res.body?.getReader();
      const decoder = new TextDecoder("utf-8");

      let done = false;
      let buffer = "";

      while (reader && !done) {
        const { value, done: readerDone } = await reader.read();
        done = readerDone;
        if (value) {
          buffer += decoder.decode(value, { stream: true });
          const parts = buffer.split("\n\n");
          buffer = parts.pop() || "";

          for (const part of parts) {
            const lines = part.split("\n");
            for (const line of lines) {
              if (line.startsWith("data: ")) {
                const dataStr = line.replace("data: ", "").trim();
                if (dataStr) {
                  try {
                    const data = JSON.parse(dataStr);
                    if (data.type === "log") {
                      setLogs((prev) => [...prev, { node: data.node, message: data.message }]);
                    } else if (data.type === "result") {
                      setResult({ verdict: data.verdict, report: data.report });
                    } else if (data.type === "error") {
                      setError(data.message);
                    }
                  } catch (err) {
                    console.error("Failed to parse JSON:", dataStr);
                  }
                }
              }
            }
          }
        }
      }
    } catch (err: any) {
      setError(err.message || "An error occurred");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  return (
    <div className="min-h-screen bg-brand-bg text-brand-text font-sans selection:bg-brand-primary/30 flex flex-col">
      <Navbar />

      <main className="flex-1 max-w-7xl w-full mx-auto px-6 pt-32 pb-24 grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

        {/* Left Sidebar (Sticky) */}
        <div className="lg:col-span-4 lg:sticky top-32 space-y-6">
          <Link href="/" className="inline-flex items-center text-sm text-brand-muted hover:text-white transition-colors mb-4">
            <ArrowLeft className="w-4 h-4 mr-2" /> Back to Home
          </Link>

          <div className="p-6 rounded-2xl bg-brand-card/50 border border-brand-border backdrop-blur-xl">
            <h1 className="text-2xl font-bold mb-2">New Analysis</h1>
            <p className="text-brand-muted text-sm mb-6">Enter a company ticker to begin AI research.</p>

            <form onSubmit={startResearch} className="relative">
              <input
                type="text"
                value={companyName}
                onChange={(e) => setCompanyName(e.target.value)}
                placeholder="e.g. AAPL or Tesla"
                className="w-full bg-brand-bg border border-brand-border rounded-xl px-4 py-3 pl-11 focus:outline-none focus:border-brand-primary transition-colors text-white placeholder-brand-muted/50"
                disabled={loading}
              />
              <Search className="absolute left-4 top-3.5 w-5 h-5 text-brand-muted" />
              <button 
                type="submit" 
                disabled={loading || !companyName}
                className="mt-4 w-full py-3 rounded-xl bg-brand-primary hover:bg-brand-secondary text-white font-semibold transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-[0_0_15px_rgba(109,94,249,0.2)]"
              >
                {loading ? (
                  <span className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /> Analyzing...</span>
                ) : "Run Analysis"}
              </button>
            </form>
          </div>

          {result && (
            <motion.div 
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              className="p-6 rounded-2xl bg-gradient-to-br from-brand-card to-brand-bg border border-brand-primary/30 shadow-[0_0_30px_rgba(109,94,249,0.1)] relative overflow-hidden"
            >
              <div className="absolute top-0 right-0 w-32 h-32 bg-brand-primary/10 blur-[50px] rounded-full" />
              <h3 className="text-sm font-semibold text-brand-muted mb-1 uppercase tracking-wider">Final Verdict</h3>
              <div className="text-4xl font-black mb-4 flex items-center gap-3">
                {result.verdict}
                {result.verdict === "INVEST" || result.verdict === "BUY" ? (
                  <div className="w-4 h-4 rounded-full bg-brand-accent shadow-[0_0_10px_#22C55E] animate-pulse" />
                ) : result.verdict === "HOLD" ? (
                  <div className="w-4 h-4 rounded-full bg-brand-warning shadow-[0_0_10px_#F59E0B] animate-pulse" />
                ) : (
                  <div className="w-4 h-4 rounded-full bg-brand-danger shadow-[0_0_10px_#EF4444] animate-pulse" />
                )}
              </div>
              <div className="flex gap-2">
                <button className="flex-1 py-2 rounded-lg bg-brand-bg border border-brand-border text-sm font-medium hover:bg-brand-border/50 transition-colors flex items-center justify-center gap-2">
                  <Download className="w-4 h-4" /> PDF
                </button>
                <button className="flex-1 py-2 rounded-lg bg-brand-bg border border-brand-border text-sm font-medium hover:bg-brand-border/50 transition-colors flex items-center justify-center gap-2">
                  <Share2 className="w-4 h-4" /> Share
                </button>
              </div>
            </motion.div>
          )}

          {error && (
            <div className="p-4 bg-brand-danger/10 border border-brand-danger/20 text-brand-danger rounded-xl text-sm flex items-start gap-3">
              <AlertTriangle className="w-5 h-5 shrink-0" />
              <p>{error}</p>
            </div>
          )}
        </div>

        {/* Main Content Area */}
        <div className="lg:col-span-8">
          <AnimatePresence mode="wait">
            {loading && !result && (
              <motion.div 
                key="loading"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="p-8 rounded-2xl bg-brand-card/30 border border-brand-border min-h-[500px] flex flex-col justify-center relative overflow-hidden"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-brand-primary/5 to-transparent -translate-x-full animate-[shimmer_2s_infinite]" />

                <div className="max-w-md mx-auto w-full space-y-6 relative z-10">
                  <div className="text-center mb-8">
                    <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-brand-primary/10 mb-4">
                      <Activity className="w-8 h-8 text-brand-primary animate-pulse" />
                    </div>
                    <h2 className="text-2xl font-bold">Agents in Motion</h2>
                    <p className="text-brand-muted">Compiling data across thousands of sources...</p>
                  </div>

                  <div className="space-y-4">
                    {logs.map((log, i) => (
                      <motion.div 
                        key={i}
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="flex items-start gap-4 p-4 rounded-xl bg-brand-bg/50 border border-brand-border/50"
                      >
                        <div className="w-2 h-2 rounded-full bg-brand-primary mt-2 shadow-[0_0_8px_#6D5EF9]" />
                        <div>
                          <div className="text-xs text-brand-muted font-mono uppercase mb-1">{log.node}</div>
                          <div className="text-sm">{log.message}</div>
                        </div>
                      </motion.div>
                    ))}
                    <div ref={logsEndRef} />
                  </div>
                </div>
              </motion.div>
            )}

            {result && (
              <motion.div 
                key="result"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="p-8 md:p-12 rounded-2xl bg-brand-card/40 border border-brand-border shadow-2xl relative"
              >
                <div className="prose prose-invert prose-brand max-w-none">
                  <div dangerouslySetInnerHTML={{ __html: formatMarkdown(result.report) }} />
                </div>
              </motion.div>
            )}

            {!loading && !result && !error && (
              <motion.div 
                key="empty"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="p-8 rounded-2xl bg-brand-card/20 border border-brand-border border-dashed min-h-[500px] flex flex-col items-center justify-center text-center text-brand-muted"
              >
                <PieChart className="w-16 h-16 mb-4 opacity-20" />
                <h3 className="text-xl font-medium text-white mb-2">Ready to Analyze</h3>
                <p className="max-w-md">Enter a company ticker in the sidebar to generate an institutional-grade investment thesis.</p>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

      </main>
    </div>
  );
}

function formatMarkdown(text: string | undefined) {
  if (!text) return "";
  let html = text
    .replace(/^### (.*$)/gim, '<h3 class="text-xl font-semibold mt-8 mb-4 text-white flex items-center gap-2"><span class="w-1 h-6 bg-brand-primary rounded-full"></span>$1</h3>')
    .replace(/^## (.*$)/gim, '<h2 class="text-3xl font-bold mt-12 mb-6 border-b border-brand-border pb-4 text-white">$1</h2>')
    .replace(/^# (.*$)/gim, '<h1 class="text-4xl font-extrabold mt-4 mb-8 text-transparent bg-clip-text bg-gradient-to-r from-white to-brand-muted">$1</h1>')
    .replace(/\*\*(.*)\*\*/gim, '<strong class="text-white font-semibold">$1</strong>')
    .replace(/\*(.*)\*/gim, '<em class="text-brand-muted italic">$1</em>')
    .replace(/\n\n/g, '</p><p class="mb-6 leading-relaxed text-brand-muted">')
    .replace(/\n/g, '<br />');

  html = html.replace(/- (.*$)/gim, '<li class="ml-4 list-disc mb-2 text-brand-muted">$1</li>');

  return `<p class="mb-6 leading-relaxed text-brand-muted">${html}</p>`;
}

