@import "tailwindcss";

@theme {
  --color-brand-bg: #050816;
  --color-brand-bg-secondary: #0F172A;
  --color-brand-card: #111827;
  --color-brand-border: rgba(255, 255, 255, 0.08);
  --color-brand-primary: #6D5EF9;
  --color-brand-secondary: #8B5CF6;
  --color-brand-success: #22C55E;
  --color-brand-warning: #F59E0B;
  --color-brand-danger: #EF4444;
  --color-brand-text: #FFFFFF;
  --color-brand-muted: #94A3B8;

  --font-sans: var(--font-inter);
}

body {
  background-color: var(--color-brand-bg);
  color: var(--color-brand-text);
  font-family: var(--font-sans);
}

::selection {
  background-color: rgba(109, 94, 249, 0.3);
}

/* Base styles for smooth scrolling */
html {
  scroll-behavior: smooth;
}

/* Markdown prose styles for research page */
.prose {
  color: var(--color-brand-text);
}
.prose h1, .prose h2, .prose h3, .prose h4, .prose h5, .prose h6 {
  color: var(--color-brand-text);
}
.prose strong {
  color: var(--color-brand-text);
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

@keyframes float {
  0% { transform: translateY(0px); }
  50% { transform: translateY(-10px); }
  100% { transform: translateY(0px); }
}

.animate-float {
  animation: float 6s ease-in-out infinite;
}

