"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Search, Loader2, Download, Share2, Activity, ShieldAlert, TrendingUp, BarChart2, CheckCircle2, History, Star, ArrowRight } from "lucide-react";
import Link from "next/link";
import { Navbar } from "@/components/layout/Navbar";

export default function ResearchPage() {
  const [companyName, setCompanyName] = useState("");
  const [loading, setLoading] = useState(false);
  const [logs, setLogs] = useState<{ node: string; message: string }[]>([]);
  const [result, setResult] = useState<{ verdict: string; report: string } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const logsEndRef = useRef<HTMLDivElement>(null);

  const startResearch = async (ticker: string = companyName) => {
    if (!ticker) return;
    setCompanyName(ticker);
    setLoading(true);
    setLogs([]);
    setResult(null);
    setError(null);

    try {
      const res = await fetch("/api/research", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ companyName: ticker }),
      });

      if (!res.ok) throw new Error("Failed to start research");

      const reader = res.body?.getReader();
      const decoder = new TextDecoder("utf-8");

      let done = false;
      let buffer = "";

      while (reader && !done) {
        const { value, done: readerDone } = await reader.read();
        done = readerDone;
        if (value) {
          buffer += decoder.decode(value, { stream: true });
          const parts = buffer.split("\n\n");
          buffer = parts.pop() || "";

          for (const part of parts) {
            const lines = part.split("\n");
            for (const line of lines) {
              if (line.startsWith("data: ")) {
                const dataStr = line.replace("data: ", "").trim();
                if (dataStr) {
                  try {
                    const data = JSON.parse(dataStr);
                    if (data.type === "log") {
                      setLogs((prev) => [...prev, { node: data.node, message: data.message }]);
                    } else if (data.type === "result") {
                      setResult({ verdict: data.verdict, report: data.report });
                    } else if (data.type === "error") {
                      setError(data.message);
                    }
                  } catch (err) {}
                }
              }
            }
          }
        }
      }
    } catch (err: any) {
      setError(err.message || "An error occurred");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  return (
    <div className="min-h-screen bg-brand-bg text-brand-text font-sans flex flex-col">
      <Navbar />

      <main className="flex-1 w-full max-w-screen-2xl mx-auto px-6 pt-24 pb-12 grid grid-cols-1 xl:grid-cols-12 gap-8">

        {/* Sticky Sidebar */}
        <div className="xl:col-span-3 space-y-6">
          <div className="sticky top-28 space-y-6">
            <div className="p-1 rounded-2xl bg-gradient-to-b from-brand-border to-transparent">
              <div className="bg-brand-bg-secondary rounded-xl p-5">
                <form 
                  onSubmit={(e) => { e.preventDefault(); startResearch(); }} 
                  className="relative group mb-6"
                >
                  <div className="absolute -inset-0.5 bg-gradient-to-r from-brand-primary to-brand-secondary rounded-xl blur opacity-30 group-hover:opacity-60 transition duration-500"></div>
                  <div className="relative flex items-center bg-brand-card border border-brand-border rounded-xl px-3 py-2">
                    <Search className="w-5 h-5 text-brand-muted" />
                    <input
                      type="text"
                      value={companyName}
                      onChange={(e) => setCompanyName(e.target.value)}
                      placeholder="Ticker (e.g. AAPL)"
                      className="w-full bg-transparent border-none outline-none text-white px-3 py-2 placeholder-brand-muted/50"
                      disabled={loading}
                    />
                    <div className="px-2 py-1 bg-brand-bg-secondary rounded border border-brand-border text-xs text-brand-muted font-mono hidden sm:block">
                      ⌘K
                    </div>
                  </div>
                </form>

                {/* Popular Stocks */}
                {!result && !loading && (
                  <div className="space-y-4">
                    <h4 className="text-xs font-bold text-brand-muted uppercase tracking-wider flex items-center gap-2">
                      <TrendingUp className="w-4 h-4" /> Trending Companies
                    </h4>
                    <div className="grid grid-cols-2 gap-2">
                      {["NVDA", "TSLA", "PLTR", "ARM"].map(ticker => (
                        <button key={ticker} onClick={() => startResearch(ticker)} className="px-3 py-2 rounded-lg bg-brand-bg border border-brand-border hover:bg-brand-card hover:border-brand-primary/50 text-sm font-medium transition-colors text-left flex justify-between items-center">
                          {ticker} <ArrowRight className="w-3 h-3 text-brand-muted" />
                        </button>
                      ))}
                    </div>

                    <h4 className="text-xs font-bold text-brand-muted uppercase tracking-wider flex items-center gap-2 mt-8">
                      <History className="w-4 h-4" /> Recent Searches
                    </h4>
                    <div className="space-y-1">
                      {["Microsoft Corp", "Apple Inc", "Alphabet Inc"].map(name => (
                        <button key={name} className="w-full px-3 py-2 rounded-lg hover:bg-brand-bg text-brand-muted hover:text-white text-sm transition-colors text-left">
                          {name}
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                {/* Result Sidebar Nav */}
                {result && (
                  <div className="space-y-2 mt-4 border-t border-brand-border/50 pt-4">
                    <h4 className="text-xs font-bold text-brand-muted uppercase tracking-wider mb-4">Report Sections</h4>
                    {["Executive Summary", "Financial Health", "Risk Analysis", "Valuation", "Final Verdict"].map(section => (
                      <a href={`#${section.toLowerCase().replace(/ /g, '-')}`} key={section} className="block px-3 py-2 rounded-lg hover:bg-brand-bg text-brand-muted hover:text-white text-sm transition-colors">
                        {section}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {/* Verdict Card */}
            {result && (
              <motion.div 
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="p-1 rounded-2xl bg-gradient-to-b from-brand-primary/50 to-transparent"
              >
                <div className="bg-brand-bg-secondary rounded-xl p-5 relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-brand-primary/10 blur-[50px] rounded-full pointer-events-none" />
                  <div className="text-xs font-bold text-brand-muted uppercase tracking-wider mb-1">Investment Score</div>
                  <div className="text-4xl font-black mb-4 flex items-center gap-3 relative z-10">
                    {result.verdict}
                    {result.verdict === "INVEST" || result.verdict === "BUY" ? (
                      <div className="w-3 h-3 rounded-full bg-brand-success shadow-[0_0_12px_#22C55E] animate-pulse" />
                    ) : result.verdict === "HOLD" ? (
                      <div className="w-3 h-3 rounded-full bg-brand-warning shadow-[0_0_12px_#F59E0B] animate-pulse" />
                    ) : (
                      <div className="w-3 h-3 rounded-full bg-brand-danger shadow-[0_0_12px_#EF4444] animate-pulse" />
                    )}
                  </div>
                  <div className="text-sm text-brand-muted mb-6">Institutional grade AI analysis completed.</div>
                  <div className="flex gap-2 relative z-10">
                    <button className="flex-1 py-2 rounded-lg bg-brand-bg border border-brand-border text-sm font-medium hover:bg-white hover:text-black transition-colors flex items-center justify-center gap-2">
                      <Download className="w-4 h-4" /> PDF
                    </button>
                    <button className="flex-1 py-2 rounded-lg bg-brand-bg border border-brand-border text-sm font-medium hover:bg-brand-card transition-colors flex items-center justify-center gap-2">
                      <Share2 className="w-4 h-4" /> Share
                    </button>
                  </div>
                </div>
              </motion.div>
            )}
          </div>
        </div>

        {/* Main Content Area */}
        <div className="xl:col-span-9">
          <AnimatePresence mode="wait">

            {/* Empty State */}
            {!loading && !result && !error && (
              <motion.div 
                key="empty"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="h-[600px] rounded-3xl bg-brand-bg-secondary border border-brand-border flex flex-col items-center justify-center text-center p-8 relative overflow-hidden"
              >
                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 mix-blend-overlay"></div>
                <div className="w-20 h-20 rounded-2xl bg-brand-card border border-brand-border flex items-center justify-center mb-6 relative z-10 shadow-2xl shadow-brand-primary/10">
                  <Activity className="w-10 h-10 text-brand-primary opacity-50" />
                </div>
                <h3 className="text-2xl font-bold text-white mb-3 relative z-10">AlphaResearch Workspace</h3>
                <p className="max-w-md text-brand-muted relative z-10">
                  Enter a ticker symbol or company name in the sidebar to generate an institutional-grade investment thesis using autonomous AI agents.
                </p>

                <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-4 w-full max-w-3xl relative z-10">
                  <div className="p-4 rounded-xl bg-brand-card/50 border border-brand-border text-left">
                    <BarChart2 className="w-5 h-5 text-brand-primary mb-2" />
                    <div className="text-sm font-semibold mb-1">Financial Analysis</div>
                    <div className="text-xs text-brand-muted">Automated DCF & Multiples</div>
                  </div>
                  <div className="p-4 rounded-xl bg-brand-card/50 border border-brand-border text-left">
                    <ShieldAlert className="w-5 h-5 text-brand-warning mb-2" />
                    <div className="text-sm font-semibold mb-1">Risk Assessment</div>
                    <div className="text-xs text-brand-muted">Operational & Market Risks</div>
                  </div>
                  <div className="p-4 rounded-xl bg-brand-card/50 border border-brand-border text-left">
                    <Star className="w-5 h-5 text-brand-success mb-2" />
                    <div className="text-sm font-semibold mb-1">Final Verdict</div>
                    <div className="text-xs text-brand-muted">Actionable Recommendations</div>
                  </div>
                </div>
              </motion.div>
            )}

            {/* Loading State */}
            {loading && !result && (
              <motion.div 
                key="loading"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="rounded-3xl bg-brand-bg-secondary border border-brand-border min-h-[600px] p-8 md:p-16 relative overflow-hidden"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-brand-primary/5 to-transparent -translate-x-full animate-[shimmer_2s_infinite]" />

                <div className="max-w-2xl mx-auto w-full relative z-10">
                  <div className="flex flex-col items-center text-center mb-16">
                    <div className="relative mb-8">
                      <div className="absolute inset-0 bg-brand-primary/20 blur-[30px] rounded-full animate-pulse" />
                      <div className="w-16 h-16 rounded-2xl bg-brand-card border border-brand-primary flex items-center justify-center relative z-10">
                        <Loader2 className="w-8 h-8 text-brand-primary animate-spin" />
                      </div>
                    </div>
                    <h2 className="text-3xl font-extrabold mb-2">Analyzing {companyName.toUpperCase()}</h2>
                    <p className="text-brand-muted">Deploying autonomous agents to gather and synthesize financial data.</p>
                  </div>

                  <div className="space-y-4">
                    {logs.map((log, i) => (
                      <motion.div 
                        key={i}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="flex items-start gap-4 p-5 rounded-2xl bg-brand-card/80 border border-brand-border/50 shadow-lg"
                      >
                        <div className="w-8 h-8 rounded-full bg-brand-primary/10 border border-brand-primary/30 flex items-center justify-center shrink-0 mt-1">
                          <CheckCircle2 className="w-4 h-4 text-brand-primary" />
                        </div>
                        <div>
                          <div className="text-xs text-brand-muted font-mono uppercase tracking-wider mb-1">{log.node}</div>
                          <div className="text-sm font-medium text-white">{log.message}</div>
                        </div>
                      </motion.div>
                    ))}
                    <div ref={logsEndRef} />
                  </div>
                </div>
              </motion.div>
            )}

            {/* Result State */}
            {result && (
              <motion.div 
                key="result"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="rounded-3xl bg-brand-bg-secondary border border-brand-border p-8 md:p-16 relative"
              >
                <div className="flex items-center gap-4 mb-12 border-b border-brand-border pb-8">
                  <div className="w-16 h-16 rounded-2xl bg-brand-card border border-brand-border flex items-center justify-center text-2xl font-bold">
                    {companyName.substring(0, 2).toUpperCase()}
                  </div>
                  <div>
                    <h1 className="text-4xl font-extrabold">{companyName.toUpperCase()}</h1>
                    <p className="text-brand-muted">AI-Generated Institutional Investment Report</p>
                  </div>
                </div>

                <div className="prose prose-invert prose-brand max-w-none prose-h2:text-2xl prose-h2:font-bold prose-h2:border-b prose-h2:border-brand-border prose-h2:pb-4 prose-h2:mt-12 prose-h3:text-xl prose-h3:text-brand-primary prose-a:text-brand-primary">
                  <div dangerouslySetInnerHTML={{ __html: formatMarkdown(result.report) }} />
                </div>
              </motion.div>
            )}

            {/* Error State */}
            {error && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="p-6 bg-brand-danger/10 border border-brand-danger/30 rounded-2xl flex items-start gap-4"
              >
                <ShieldAlert className="w-6 h-6 text-brand-danger shrink-0" />
                <div>
                  <h3 className="font-bold text-brand-danger mb-1">System Error</h3>
                  <p className="text-brand-danger/80">{error}</p>
                </div>
              </motion.div>
            )}

          </AnimatePresence>
        </div>
      </main>
    </div>
  );
}

function formatMarkdown(text: string | undefined) {
  if (!text) return "";
  let html = text
    .replace(/^### (.*$)/gim, '<h3>$1</h3>')
    .replace(/^## (.*$)/gim, '<h2 id="$1">$1</h2>')
    .replace(/^# (.*$)/gim, '<h1>$1</h1>')
    .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
    .replace(/\*(.*)\*/gim, '<em>$1</em>')
    .replace(/\n\n/g, '</p><p>')
    .replace(/\n/g, '<br />');

  html = html.replace(/- (.*$)/gim, '<li>$1</li>');
  html = html.replace(/(<li>.*<\/li>)/gim, '<ul>$1</ul>').replace(/<\/ul><ul>/gim, '');

  return `<p>${html}</p>`;
}

