@import "tailwindcss";

@theme {
  --color-brand-bg: #17351D;
  --color-brand-bg-secondary: #1D3A22;
  --color-brand-bg-alt: #19351E;
  --color-brand-card: #18341D;

  --color-brand-text: #F7F3EC;
  --color-brand-text-secondary: #C9C5BB;
  --color-brand-muted: #9E9A90;

  --color-brand-gold: #D5A93A;
  --color-brand-gold-hover: #E2B84C;

  --color-brand-success: #4FAE64;
  --color-brand-warning: #D5A93A;
  --color-brand-danger: #C85A54;

  --color-brand-border: rgba(213, 169, 58, 0.18);
  --color-brand-border-secondary: rgba(255, 255, 255, 0.08);
  --color-brand-divider: rgba(255, 255, 255, 0.06);

