"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Search, Loader2, ArrowRight } from "lucide-react";
import Link from "next/link";
import { Navbar } from "@/components/layout/Navbar";
import { Footer } from "@/components/layout/Footer";

export default function ResearchPage() {
  const [companyName, setCompanyName] = useState("");
  const [loading, setLoading] = useState(false);
  const [logs, setLogs] = useState<{ node: string; message: string }[]>([]);
  const [result, setResult] = useState<{ verdict: string; report: string } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const logsEndRef = useRef<HTMLDivElement>(null);

  const startResearch = async (ticker: string = companyName) => {
    if (!ticker) return;
    setCompanyName(ticker);
    setLoading(true);
    setLogs([]);
    setResult(null);
    setError(null);

    try {
      const res = await fetch("/api/research", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ companyName: ticker }),
      });

      if (!res.ok) throw new Error("Failed to start research");

      const reader = res.body?.getReader();
      const decoder = new TextDecoder("utf-8");

      let done = false;
      let buffer = "";

      while (reader && !done) {
        const { value, done: readerDone } = await reader.read();
        done = readerDone;
        if (value) {
          buffer += decoder.decode(value, { stream: true });
          const parts = buffer.split("\n\n");
          buffer = parts.pop() || "";

          for (const part of parts) {
            const lines = part.split("\n");
            for (const line of lines) {
              if (line.startsWith("data: ")) {
                const dataStr = line.replace("data: ", "").trim();
                if (dataStr) {
                  try {
                    const data = JSON.parse(dataStr);
                    if (data.type === "log") {
                      setLogs((prev) => [...prev, { node: data.node, message: data.message }]);
                    } else if (data.type === "result") {
                      setResult({ verdict: data.verdict, report: data.report });
                    } else if (data.type === "error") {
                      setError(data.message);
                    }
                  } catch (err) {}
                }
              }
            }
          }
        }
      }
    } catch (err: any) {
      setError(err.message || "An error occurred");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  return (
    <div className="min-h-screen bg-brand-bg text-brand-text font-sans">
      <Navbar />

      <main className="max-w-[1200px] mx-auto px-6 pt-[160px] pb-[160px]">

        {/* Search Header */}
        <div className="mb-[96px]">
          <form onSubmit={(e) => { e.preventDefault(); startResearch(); }} className="max-w-3xl">
            <div className="flex items-center bg-brand-input-bg border border-brand-input-border rounded-[14px] overflow-hidden p-3 transition-colors focus-within:border-brand-gold/50">
              <Search className="w-5 h-5 text-brand-gold ml-4 shrink-0" />
              <input
                type="text"
                value={companyName}
                onChange={(e) => setCompanyName(e.target.value)}
                placeholder="Enter ticker (e.g. AAPL) to generate an institutional report"
                className="w-full bg-transparent border-none outline-none text-brand-text px-6 py-4 text-[18px] font-sans placeholder-brand-muted"
                disabled={loading}
              />
              <button 
                type="submit" 
                className="px-8 py-[18px] bg-brand-button-bg text-brand-button-text font-medium rounded-[12px] hover:bg-brand-gold-hover transition-colors hidden sm:block whitespace-nowrap text-[18px]"
                disabled={loading}
              >
                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : "Analyze"}
              </button>
            </div>
          </form>
        </div>

        {/* Content Area */}
        <AnimatePresence mode="wait">

          {/* Empty State */}
          {!loading && !result && !error && (
            <motion.div 
              key="empty"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="border-t border-brand-divider pt-[96px]"
            >
              <h1 className="font-serif text-[56px] font-normal leading-[1.1] mb-12 max-w-2xl">
                Deep fundamental research.<br/>Executed autonomously.
              </h1>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-[64px]">
                <div>
                  <h3 className="font-serif text-[34px] font-normal mb-4">Trending Equities</h3>
                  <div className="space-y-4">
                    {["NVIDIA Corporation (NVDA)", "Tesla, Inc. (TSLA)", "Palantir Technologies (PLTR)"].map((ticker) => (
                      <button 
                        key={ticker} 
                        onClick={() => {
                          const symbol = ticker.match(/\(([^)]+)\)/)?.[1];
                          if(symbol) startResearch(symbol);
                        }}
                        className="flex items-center justify-between w-full py-4 border-b border-brand-divider text-left hover:text-brand-gold transition-colors text-[18px] font-light"
                      >
                        {ticker} <ArrowRight className="w-5 h-5 text-brand-muted" />
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <h3 className="font-serif text-[34px] font-normal mb-4">Recent Analyses</h3>
                  <div className="space-y-4">
                    {["Apple Inc. (AAPL)", "Microsoft Corp (MSFT)"].map((ticker) => (
                      <div key={ticker} className="flex items-center justify-between w-full py-4 border-b border-brand-divider text-left text-brand-muted text-[18px] font-light">
                        {ticker}
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {/* Loading State */}
          {loading && !result && (
            <motion.div 
              key="loading"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="border-t border-brand-divider pt-[96px]"
            >
              <div className="flex items-center gap-6 mb-[64px]">
                <Loader2 className="w-8 h-8 text-brand-gold animate-spin" />
                <h2 className="font-serif text-[56px] font-normal leading-[1.1]">
                  Generating Committee Report
                </h2>
              </div>

              <div className="max-w-3xl">
                {logs.map((log, i) => (
                  <motion.div 
                    key={i}
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="flex gap-8 py-6 border-b border-brand-divider"
                  >
                    <div className="w-[120px] shrink-0 text-[14px] font-medium tracking-[2px] uppercase text-brand-gold">
                      {log.node}
                    </div>
                    <div className="text-[18px] font-light text-brand-text-secondary">
                      {log.message}
                    </div>
                  </motion.div>
                ))}
                <div ref={logsEndRef} />
              </div>
            </motion.div>
          )}

          {/* Result State - Editorial Report */}
          {result && (
            <motion.div 
              key="result"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.8 }}
              className="bg-brand-card border border-brand-border-secondary rounded-[10px] p-[64px] md:p-[96px] shadow-2xl"
            >
              <div className="flex flex-col md:flex-row md:items-end justify-between border-b border-brand-divider pb-12 mb-16 gap-8">
                <div>
                  <div className="text-brand-gold text-[14px] font-medium tracking-[2px] uppercase mb-4">
                    Investment Committee Memorandum
                  </div>
                  <h1 className="font-serif text-[72px] font-normal leading-[1.05] tracking-tight">
                    {companyName.toUpperCase()}
                  </h1>
                </div>

                <div className="text-right">
                  <div className="text-[14px] font-medium tracking-[2px] uppercase text-brand-muted mb-4">
                    Verdict
                  </div>
                  <div className="inline-flex items-center gap-4 px-8 py-4 bg-[#122A17] border border-brand-border rounded-[10px]">
                    <div className={`w-3 h-3 rounded-full ${
                      result.verdict === "INVEST" || result.verdict === "BUY" ? "bg-brand-success" : 
                      result.verdict === "HOLD" ? "bg-brand-warning" : "bg-brand-danger"
                    }`} />
                    <span className="font-serif text-[34px] font-normal text-brand-gold">
                      {result.verdict}
                    </span>
                  </div>
                </div>
              </div>

              {/* Editorial Markdown Rendering */}
              <div className="prose prose-invert max-w-none 
                prose-p:text-[20px] prose-p:font-light prose-p:leading-[1.8] prose-p:text-brand-text-secondary prose-p:mb-8
                prose-h1:font-serif prose-h1:text-[56px] prose-h1:font-normal prose-h1:text-brand-text prose-h1:mt-16 prose-h1:mb-8
                prose-h2:font-serif prose-h2:text-[34px] prose-h2:font-normal prose-h2:text-brand-gold prose-h2:border-b prose-h2:border-brand-divider prose-h2:pb-4 prose-h2:mt-16 prose-h2:mb-8
                prose-h3:font-serif prose-h3:text-[24px] prose-h3:font-normal prose-h3:text-brand-text prose-h3:mt-12 prose-h3:mb-6
                prose-ul:text-[20px] prose-ul:font-light prose-ul:text-brand-text-secondary prose-ul:leading-[1.8]
                prose-li:my-3
                prose-strong:text-brand-text prose-strong:font-medium
              ">
                <div dangerouslySetInnerHTML={{ __html: formatMarkdown(result.report) }} />
              </div>

              <div className="mt-32 pt-12 border-t border-brand-divider flex justify-between items-center">
                <div className="text-[14px] text-brand-muted">
                  Generated by AlphaResearch AI System.<br/>
                  Confidential and proprietary.
                </div>
                <button className="px-8 py-[18px] bg-brand-button-bg text-brand-button-text font-medium rounded-[12px] hover:bg-brand-gold-hover transition-colors">
                  Download PDF
                </button>
              </div>
            </motion.div>
          )}

          {/* Error State */}
          {error && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="p-8 border border-brand-danger bg-brand-danger/10 text-brand-danger text-[18px] rounded-[10px]"
            >
              System Error: {error}
            </motion.div>
          )}

        </AnimatePresence>
      </main>

      <Footer />
    </div>
  );
}

function formatMarkdown(text: string | undefined) {
  if (!text) return "";
  let html = text
    .replace(/^### (.*$)/gim, '<h3>$1</h3>')
    .replace(/^## (.*$)/gim, '<h2>$1</h2>')
    .replace(/^# (.*$)/gim, '<h1>$1</h1>')
    .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
    .replace(/\*(.*)\*/gim, '<em>$1</em>')
    .replace(/\n\n/g, '</p><p>')
    .replace(/\n/g, '<br />');

  html = html.replace(/- (.*$)/gim, '<li>$1</li>');
  html = html.replace(/(<li>.*<\/li>)/gim, '<ul>$1</ul>').replace(/<\/ul><ul>/gim, '');

  return `<p>${html}</p>`;
}

import Link from "next/link";
import { Navbar } from "@/components/layout/Navbar";
import { Footer } from "@/components/layout/Footer";

export default function NotFound() {
  return (
    <div className="min-h-screen bg-brand-bg text-brand-text font-sans flex flex-col">
      <Navbar />

      <main className="flex-1 flex flex-col items-center justify-center px-6 text-center">
        <span className="text-brand-gold text-[14px] font-medium tracking-[2px] uppercase mb-8 block">Error 404</span>
        <h1 className="font-serif text-[72px] font-normal leading-[1.05] mb-8">
          Record not found.
        </h1>
        <p className="text-[20px] text-brand-text-secondary font-light max-w-md mb-12">
          The requested document or terminal directory has been moved, reclassified, or does not exist.
        </p>

        <Link 
          href="/"
          className="inline-flex items-center justify-center px-10 py-[18px] rounded-[12px] bg-brand-button-bg text-brand-button-text text-[18px] font-medium transition-colors hover:bg-brand-gold-hover"
        >
          Return to Hub
        </Link>
      </main>

      <Footer />
    </div>
  );
}

